/**
 * @fileoverview Checkbox events.
 * @module module/Checkbox/events
 */

import { emitEvent } from '../shared/emitEvent.js';

export function bindEvents(box, root, ctx) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };
    const el   = box[0];

    const handleToggle = () => {
        if (ctx.disabled()) return;
        ctx.toggle();
    };

    el.addEventListener('click', handleToggle, opts);

    el.addEventListener('keydown', (e) => {
        if (e.key === ' ' || e.key === 'Enter') {
            e.preventDefault();
            handleToggle();
        }
    }, opts);

    // Also allow clicking the root (label area)
    root[0].addEventListener('click', (e) => {
        if (e.target === el || el.contains(e.target)) return;
        handleToggle();
    }, opts);

    return ac;
}
