/**
 * @fileoverview Checkbox view — DOM setup and state effects.
 * @module module/Checkbox/view
 */

import { CLS, PART } from './constants.js';

export const SM_EFFECTS = {
    unchecked({ box, check }) {
        box.removeClass(CLS.CHECKED).removeClass(CLS.INDETERMINATE);
        check.removeClass(CLS.CHECKED).removeClass(CLS.INDETERMINATE);
        box[0].setAttribute('aria-checked', 'false');
    },
    checked({ box, check }) {
        box.addClass(CLS.CHECKED).removeClass(CLS.INDETERMINATE);
        check.addClass(CLS.CHECKED).removeClass(CLS.INDETERMINATE);
        box[0].setAttribute('aria-checked', 'true');
    },
    indeterminate({ box, check }) {
        box.addClass(CLS.INDETERMINATE).removeClass(CLS.CHECKED);
        check.addClass(CLS.INDETERMINATE).removeClass(CLS.CHECKED);
        box[0].setAttribute('aria-checked', 'mixed');
    },
    disabled({ root, box }) {
        root.addClass(CLS.DISABLED);
        box[0].setAttribute('aria-disabled', 'true');
        box[0].setAttribute('tabindex', '-1');
    },
    'disabled:exit'({ root, box }) {
        root.removeClass(CLS.DISABLED);
        box[0].removeAttribute('aria-disabled');
        box[0].setAttribute('tabindex', '0');
    },
};

/** Check SVG icon (tick mark) */
const CHECK_SVG = '<svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M3.5 8.5L6.5 11.5L12.5 4.5"/></svg>';

/** Indeterminate dash SVG */
const DASH_SVG = '<svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><path d="M4 8H12"/></svg>';

/**
 * Build checkbox DOM.
 */
export function setupDOM(root, config) {
    const { size, label } = config;

    root.addClass(CLS.ROOT);
    // Reset legacy .checkbox styles from _utilities.sass
    Object.assign(root[0].style, { appearance: 'unset', width: 'auto', height: 'auto', border: 'none', background: 'none', flexShrink: 'unset', verticalAlign: 'unset' });
    PART.ROOT.apply(root);

    if (size === 'sm') {
        PART.SM_ROOT.apply(root);
    } else if (size === 'lg') {
        PART.LG_ROOT.apply(root);
    }

    const el = root[0];

    // Box
    const box = PART.BOX.create({
        role: 'checkbox',
        'aria-checked': 'false',
        tabindex: '0',
    });
    root.append(box);

    // Check icon container
    const check = PART.CHECK.create();
    check[0].innerHTML = CHECK_SVG;
    box.append(check);

    // Label
    let labelEl = null;
    if (label) {
        labelEl = PART.LABEL.create();
        labelEl.text(label);
        root.append(labelEl);
    }

    return { box, check, labelEl, CHECK_SVG, DASH_SVG };
}

export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT);
    root[0].innerHTML = '';
}
