/**
 * @fileoverview Checkbox component — modular entry point.
 * @module module/Checkbox
 */

import { default as razyui } from '../../index.js';
import { StateMachine } from '../shared/StateMachine.js';
import { CheckboxDef as DEF } from '../Checkbox.def.js';

import { DEFAULTS, CLS } from './constants.js';
import { SM_EFFECTS, setupDOM, cleanupDOM } from './view.js';
import { bindEvents } from './events.js';
import { emitEvent } from '../shared/emitEvent.js';

const Checkbox = class {
    #root    = null;
    #destroyed = false;
    #box     = null;
    #check   = null;
    #sm      = null;
    #config  = {};
    #eventAC = null;
    #checked = false;
    #indeterminate = false;
    #checkSVG = '';
    #dashSVG  = '';
    #hiddenInput = null;

    constructor(selector, config = {}) {
        const root = razyui(selector);

        if (!root.length) {
            console.warn('Checkbox: element not found \u2192', selector);
            return;
        }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#init();
    }

    #init() {
        const root   = this.#root;
        const config = this.#config;

        const { box, check, labelEl, CHECK_SVG, DASH_SVG } = setupDOM(root, config);
        this.#box   = box;
        this.#check = check;
        this.#checkSVG = CHECK_SVG;
        this.#dashSVG  = DASH_SVG;

        const sm = new StateMachine({
            initial: 'unchecked',
            states: {
                unchecked:     { on: { CHECK: 'checked', INDETERMINATE: 'indeterminate', DISABLE: 'disabled' } },
                checked:       { on: { UNCHECK: 'unchecked', INDETERMINATE: 'indeterminate', DISABLE: 'disabled' } },
                indeterminate: { on: { CHECK: 'checked', UNCHECK: 'unchecked', DISABLE: 'disabled' } },
                disabled:      { on: { ENABLE: 'unchecked', ENABLE_CHECKED: 'checked' } },
            },
            effects: SM_EFFECTS,
        }, { root, box, check });
        this.#sm = sm;

        this.#eventAC = bindEvents(box, root, {
            disabled: () => this.#sm.current === 'disabled',
            toggle: () => this.toggle(),
        });

        // Initial state
        if (config.disabled) {
            if (config.checked) {
                sm.send('CHECK');
                this.#checked = true;
            }
            sm.send('DISABLE');
        } else if (config.indeterminate) {
            sm.send('INDETERMINATE');
            this.#indeterminate = true;
            this.#check[0].innerHTML = this.#dashSVG;
        } else if (config.checked) {
            sm.send('CHECK');
            this.#checked = true;
        }

        // Hidden input for native form submission
        if (config.name) {
            const hidden = document.createElement('input');
            hidden.type = 'hidden';
            hidden.name = config.name;
            hidden.value = this.#checked ? (config.value ?? 'on') : '';
            root[0].appendChild(hidden);
            this.#hiddenInput = hidden;
        }
    }

    toggle() {
        if (this.#sm.current === 'disabled') return;

        this.#indeterminate = false;
        this.#checked = !this.#checked;

        if (this.#checked) {
            this.#sm.send('CHECK');
            this.#check[0].innerHTML = this.#checkSVG;
        } else {
            this.#sm.send('UNCHECK');
            this.#check[0].innerHTML = this.#checkSVG;
        }

        if (this.#hiddenInput) this.#hiddenInput.value = this.#checked ? (this.#config.value ?? 'on') : '';
        emitEvent(this.#root[0], 'change', { checked: this.#checked, value: this.#config.value });
        this.#config.onChange?.(this.#checked);
    }

    get checked() { return this.#checked; }
    set checked(v) {
        if (v === this.#checked) return;
        this.#checked = v;
        this.#indeterminate = false;
        this.#sm.send(v ? 'CHECK' : 'UNCHECK');
        this.#check[0].innerHTML = this.#checkSVG;
        if (this.#hiddenInput) this.#hiddenInput.value = v ? (this.#config.value ?? 'on') : '';
        emitEvent(this.#root[0], 'change', { checked: this.#checked, value: this.#config.value });
    }

    get indeterminate() { return this.#indeterminate; }
    set indeterminate(v) {
        this.#indeterminate = v;
        if (v) {
            this.#sm.send('INDETERMINATE');
            this.#check[0].innerHTML = this.#dashSVG;
        } else {
            this.#sm.send(this.#checked ? 'CHECK' : 'UNCHECK');
            this.#check[0].innerHTML = this.#checkSVG;
        }
    }

    setDisabled(disabled) {
        if (disabled) this.#sm.send('DISABLE');
        else this.#sm.send(this.#checked ? 'ENABLE_CHECKED' : 'ENABLE');
    }

    setInvalid(invalid) {
        this.#root.toggleClass(CLS.INVALID, !!invalid);
        this.#root[0][invalid ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    focus() { this.#box[0]?.focus(); }
    blur()  { this.#box[0]?.blur(); }

    clear() {
        this.checked = false;
        this.indeterminate = false;
    }

    getControl() {
        const self = this;
        return {
            get checked()       { return self.checked; },
            set checked(v)      { self.checked = v; },
            get indeterminate() { return self.indeterminate; },
            set indeterminate(v){ self.indeterminate = v; },
            get disabled()      { return self.#sm.current === 'disabled'; },
            set disabled(v)     { self.setDisabled(v); },
            get value()         { return self.#config.value; },
            set value(v)        { self.#config.value = v; },
            get name()          { return self.#config.name; },
            set name(v)         { self.#config.name = v; if (self.#hiddenInput) self.#hiddenInput.name = v; },
            get required()      { return self.#config.required ?? false; },
            set required(v)     { self.#config.required = !!v; if (self.#hiddenInput) self.#hiddenInput.required = !!v; self.#root[0].setAttribute('aria-required', String(!!v)); },
            toggle:             () => self.toggle(),
            setDisabled:        (v) => self.setDisabled(v),
            setInvalid:         (v) => self.setInvalid(v),
            checkValidity:      () => self.#hiddenInput ? self.#hiddenInput.checkValidity() : true,
            reportValidity:     () => self.#hiddenInput ? self.#hiddenInput.reportValidity() : true,
            setCustomValidity:  (m) => { if (self.#hiddenInput) self.#hiddenInput.setCustomValidity(m || ''); self.setInvalid(!!m); },
            get label()         { return self.#root[0].getAttribute('aria-label'); },
            set label(v)        { v ? self.#root[0].setAttribute('aria-label', v) : self.#root[0].removeAttribute('aria-label'); },
            get labelledby()    { return self.#root[0].getAttribute('aria-labelledby'); },
            set labelledby(v)   { v ? self.#root[0].setAttribute('aria-labelledby', v) : self.#root[0].removeAttribute('aria-labelledby'); },
            get describedby()   { return self.#root[0].getAttribute('aria-describedby'); },
            set describedby(v)  { v ? self.#root[0].setAttribute('aria-describedby', v) : self.#root[0].removeAttribute('aria-describedby'); },
            focus:              () => self.focus(),
            blur:               () => self.blur(),
            clear:              () => self.clear(),
            destroy:            () => self.destroy(),
            get element()       { return self.#root[0]; },
            get destroyed()     { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        if (this.#hiddenInput) { this.#hiddenInput.remove(); this.#hiddenInput = null; }
        cleanupDOM(this.#root);
    }
};

export default Checkbox;
