/**
 * @fileoverview Checkbox constants — CSS classes, defaults, JIT parts.
 * @module module/Checkbox/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:     'checkbox',
    BOX:      'checkbox-box',
    CHECK:    'checkbox-check',
    LABEL:    'checkbox-label',
    CHECKED:  'is-checked',
    INDETERMINATE: 'is-indeterminate',
    DISABLED: 'is-disabled',
    INVALID:  'is-invalid',
});

/** Default configuration */
export const DEFAULTS = Object.freeze({
    checked: false,
    disabled: false,
    indeterminate: false,
    size: 'md',
    label: '',
    value: '',
    name: null,
    onChange: null,
});

/** Semantic parts */
export const PART = defineParts('Checkbox', {
    ROOT        : { class: 'checkbox-container', aliases: ['root', 'container'] },
    BOX         : { class: 'checkbox-box', aliases: ['box'], tag: 'span' },
    CHECK       : { class: 'checkbox-check', aliases: ['check', 'icon'], tag: 'span' },
    LABEL       : { class: 'checkbox-label', aliases: ['label'], tag: 'span' },
    SM_ROOT     : { class: 'checkbox-container-sm', aliases: ['sm'] },
    LG_ROOT     : { class: 'checkbox-container-lg', aliases: ['lg'] },
});

PART.ROOT.jit     = 'inline-flex items-center gap-[var(--cb-gap)] cursor-pointer select-none [font-family:var(--cb-font-stack)] text-[var(--cb-font-size)] {is-disabled}:opacity-50 {is-disabled}:cursor-not-allowed';
PART.BOX.jit      = 'relative flex items-center justify-center shrink-0 w-[var(--cb-size)] h-[var(--cb-size)] bg-[var(--cb-bg)] [border:2px_solid_var(--cb-border)] rounded-[var(--cb-radius)] ' + TRANSITION_COLORS + ' {is-checked}:bg-[var(--cb-checked-bg)] {is-checked}:[border-color:var(--cb-checked-border)] {is-indeterminate}:bg-[var(--cb-checked-bg)] {is-indeterminate}:[border-color:var(--cb-checked-border)] hover:[border-color:var(--cb-hover-border)] focus-visible:[outline:2px_solid_var(--cb-checked-bg)] focus-visible:[outline-offset:2px]';
PART.CHECK.jit    = 'absolute w-[60%] h-[60%] fg-[var(--cb-check-color)] opacity-0 [transition:opacity_.15s] {is-checked}:opacity-100 {is-indeterminate}:opacity-100';
PART.LABEL.jit    = 'fg-[var(--cb-text)] [line-height:1.4]';
PART.SM_ROOT.jit  = '[--cb-size:var(--cb-sm-size)] [--cb-font-size:var(--cb-sm-font-size)]';
PART.LG_ROOT.jit  = '[--cb-size:var(--cb-lg-size)] [--cb-font-size:var(--cb-lg-font-size)]';